import React, { useEffect, useState } from 'react'
import { seasonService, pondService } from '../../services/api'
import '../../styles/dashboard.css'

const emptyCreateForm = {
  pondId: '',
  seasonName: '',
  startDate: '',
  shrimpType: '',
  density: '',
}

const emptyHarvestForm = {
  actualHarvestDate: '',
  note: '',
}

const formatVietnameseDate = (value) => {
  if (!value) return '-'
  const date = new Date(value)
  if (Number.isNaN(date.getTime())) return value

  return new Intl.DateTimeFormat('vi-VN', {
    day: '2-digit',
    month: '2-digit',
    year: 'numeric',
    timeZone: 'Asia/Ho_Chi_Minh',
  }).format(date)
}

const formatRoundedNumber = (value) => {
  if (value === null || value === undefined || value === '') return '-'
  const numberValue = Number(value)
  if (Number.isNaN(numberValue)) return value
  return String(Math.round(numberValue))
}

const ManagerSeasons = () => {
  const [seasons, setSeasons] = useState([])
  const [ponds, setPonds] = useState([])
  const [loading, setLoading] = useState(true)
  const [saving, setSaving] = useState(false)
  const [error, setError] = useState('')
  const [showCreateModal, setShowCreateModal] = useState(false)
  const [showHarvestModal, setShowHarvestModal] = useState(false)
  const [selectedSeason, setSelectedSeason] = useState(null)
  const [createForm, setCreateForm] = useState(emptyCreateForm)
  const [harvestForm, setHarvestForm] = useState(emptyHarvestForm)

  // Filter states
  const [filterPondId, setFilterPondId] = useState('')
  const [filterPondSearch, setFilterPondSearch] = useState('')
  const [filterStatus, setFilterStatus] = useState('')
  const [filterShrimpType, setFilterShrimpType] = useState('')
  const [filterShrimpTypeSearch, setFilterShrimpTypeSearch] = useState('')
  const [filterSeasonName, setFilterSeasonName] = useState('')
  const [openPondDropdown, setOpenPondDropdown] = useState(false)
  const [openShrimpTypeDropdown, setOpenShrimpTypeDropdown] = useState(false)

  useEffect(() => {
    fetchData()
  }, [])

  const fetchData = async () => {
    try {
      setLoading(true)
      const [seasonsRes, pondsRes] = await Promise.all([
        seasonService.getAllSeasons(),
        pondService.getAllPonds(),
      ])
      setSeasons(seasonsRes?.data?.data || [])
      setPonds(pondsRes?.data?.data || [])
      setError('')
    } catch (err) {
      setError(err?.response?.data?.message || 'Không tải được dữ liệu mùa vụ')
    } finally {
      setLoading(false)
    }
  }

  const getPondName = (pondId) => {
    if (!pondId) return '-'
    const found = ponds.find((p) => p.pond_id === pondId)
    return found ? (found.pond_name || found.pond_code) : '-'
  }

  // Get unique shrimp types for filter dropdown
  const uniqueShrimpTypes = Array.from(new Set(seasons.map((s) => s.shrimp_type).filter(Boolean))).sort()

  // Get unique ponds (with filter logic)
  const uniquePonds = ponds

  // Dependent filtering logic
  // If pond selected, get only shrimp types for that pond
  const shrimpTypesForSelectedPond = filterPondId
    ? Array.from(new Set(
        seasons
          .filter((s) => s.pond_id === Number(filterPondId))
          .map((s) => s.shrimp_type)
          .filter(Boolean)
      )).sort()
    : uniqueShrimpTypes

  // If shrimp type selected, get only ponds with that shrimp type
  const pondsForSelectedShrimpType = filterShrimpType
    ? Array.from(new Set(
        seasons
          .filter((s) => s.shrimp_type === filterShrimpType)
          .map((s) => ponds.find((p) => p.pond_id === s.pond_id))
          .filter(Boolean)
      )).sort((a, b) => (a.pond_code || '').localeCompare(b.pond_code || ''))
    : uniquePonds

  // Apply filters to seasons
  const filteredSeasons = seasons.filter((season) => {
    if (filterPondId && season.pond_id !== Number(filterPondId)) return false
    if (filterStatus && season.status !== filterStatus) return false
    if (filterShrimpType && season.shrimp_type !== filterShrimpType) return false
    if (filterSeasonName && !season.season_name.toLowerCase().includes(filterSeasonName.toLowerCase())) return false
    return true
  })

  // Reset filters function
  const resetFilters = () => {
    setFilterPondId('')
    setFilterPondSearch('')
    setFilterStatus('')
    setFilterShrimpType('')
    setFilterShrimpTypeSearch('')
    setFilterSeasonName('')
    setOpenPondDropdown(false)
    setOpenShrimpTypeDropdown(false)
  }

  // Filter ponds for dropdown based on search + dependent filtering
  const filteredPonds = filterPondSearch
    ? pondsForSelectedShrimpType.filter((pond) =>
        `${pond.pond_code} ${pond.pond_name}`.toLowerCase().includes(filterPondSearch.toLowerCase())
      )
    : pondsForSelectedShrimpType

  // Filter shrimp types for dropdown based on search + dependent filtering
  const filteredShrimpTypes = filterShrimpTypeSearch
    ? shrimpTypesForSelectedPond.filter((type) =>
        type.toLowerCase().includes(filterShrimpTypeSearch.toLowerCase())
      )
    : shrimpTypesForSelectedPond

  // Handle pond selection from dropdown
  const handleSelectPond = (pondId, pondName, pondCode) => {
    setFilterPondId(pondId)
    setFilterPondSearch(`${pondCode} - ${pondName}`)
    setOpenPondDropdown(false)
    
    // If shrimp type is selected but not available in new pond, clear it
    if (filterShrimpType) {
      const shrimpTypesInNewPond = Array.from(new Set(
        seasons
          .filter((s) => s.pond_id === pondId)
          .map((s) => s.shrimp_type)
          .filter(Boolean)
      ))
      if (!shrimpTypesInNewPond.includes(filterShrimpType)) {
        setFilterShrimpType('')
        setFilterShrimpTypeSearch('')
      }
    }
  }

  // Handle shrimp type selection from dropdown
  const handleSelectShrimpType = (type) => {
    setFilterShrimpType(type)
    setFilterShrimpTypeSearch(type)
    setOpenShrimpTypeDropdown(false)
    
    // If pond is selected but doesn't have this shrimp type, clear it
    if (filterPondId) {
      const hasType = seasons.some(
        (s) => s.pond_id === Number(filterPondId) && s.shrimp_type === type
      )
      if (!hasType) {
        setFilterPondId('')
        setFilterPondSearch('')
      }
    }
  }

  const openCreateModal = () => {
    setCreateForm(emptyCreateForm)
    setShowCreateModal(true)
  }

  const openHarvestModal = (season) => {
    setSelectedSeason(season)
    setHarvestForm(emptyHarvestForm)
    setShowHarvestModal(true)
  }

  const handleCreateChange = (field, value) => {
    setCreateForm((prev) => ({ ...prev, [field]: value }))
  }

  const handleHarvestChange = (field, value) => {
    setHarvestForm((prev) => ({ ...prev, [field]: value }))
  }

  const handleCreateSubmit = async (event) => {
    event.preventDefault()
    try {
      setSaving(true)
      await seasonService.createSeason({
        pondId: Number(createForm.pondId),
        seasonName: createForm.seasonName.trim(),
        startDate: createForm.startDate,
        shrimpType: createForm.shrimpType.trim(),
        density: Number(createForm.density),
      })
      setShowCreateModal(false)
      setCreateForm(emptyCreateForm)
      await fetchData()
    } catch (err) {
      setError(err?.response?.data?.message || 'Không tạo được mùa vụ')
    } finally {
      setSaving(false)
    }
  }

  const handleHarvestSubmit = async (event) => {
    event.preventDefault()
    try {
      setSaving(true)
      await seasonService.harvestSeason(selectedSeason.season_id, {
        actualHarvestDate: harvestForm.actualHarvestDate,
        note: harvestForm.note.trim() || null,
      })
      setShowHarvestModal(false)
      setSelectedSeason(null)
      setHarvestForm(emptyHarvestForm)
      await fetchData()
    } catch (err) {
      setError(err?.response?.data?.message || 'Không kết thúc mùa vụ')
    } finally {
      setSaving(false)
    }
  }

  return (
    <div className="dashboard-container">
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 20 }}>
        <div>
          <h2>Quản lý mùa vụ</h2>
          <p style={{ margin: 0, color: '#666' }}>Manager tạo mùa vụ mới, theo dõi tiến độ và kết thúc mùa vụ.</p>
        </div>
        <button className="btn btn-primary" onClick={openCreateModal}>
          + Tạo mùa vụ mới
        </button>
      </div>

      {error && <div className="alert alert-danger">{error}</div>}

      {/* Filter Section */}
      <div className="card" style={{ marginBottom: 20 }}>
        <h3 style={{ marginTop: 0 }}>🔍 Bộ lọc</h3>
        <div style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))',
          gap: 12,
          marginBottom: 12,
        }}>
          {/* Searchable Pond Filter */}
          <div className="form-group" style={{ margin: 0, position: 'relative' }}>
            <label style={{ fontSize: '12px', fontWeight: 600, marginBottom: 4, display: 'block' }}>Lọc theo ao</label>
            <div style={{ display: 'flex', alignItems: 'center', gap: 0 }}>
              <input
                className="input"
                type="text"
                value={filterPondSearch}
                onChange={(e) => {
                  setFilterPondSearch(e.target.value)
                  if (!openPondDropdown) setOpenPondDropdown(true)
                }}
                onFocus={() => setOpenPondDropdown(true)}
                placeholder="Nhập ao hoặc click ▼"
                style={{ margin: 0, borderRadius: '4px 0 0 4px', flex: 1 }}
              />
              <button
                className="btn"
                onClick={() => setOpenPondDropdown(!openPondDropdown)}
                style={{
                  margin: 0,
                  padding: '8px 12px',
                  borderRadius: '0 4px 4px 0',
                  border: '1px solid #ddd',
                  borderLeft: 'none',
                  cursor: 'pointer',
                  backgroundColor: '#f5f5f5',
                  fontSize: '16px',
                }}
              >
                ▼
              </button>
            </div>
            {openPondDropdown && (
              <div
                style={{
                  position: 'absolute',
                  top: '100%',
                  left: 0,
                  right: 0,
                  backgroundColor: 'white',
                  border: '1px solid #ddd',
                  borderRadius: '4px',
                  marginTop: '4px',
                  maxHeight: '200px',
                  overflowY: 'auto',
                  zIndex: 10,
                  boxShadow: '0 4px 6px rgba(0,0,0,0.1)',
                }}
              >
                <div
                  onClick={() => {
                    setFilterPondId('')
                    setFilterPondSearch('')
                    setOpenPondDropdown(false)
                  }}
                  style={{
                    padding: '8px 12px',
                    cursor: 'pointer',
                    backgroundColor: !filterPondId ? '#f0f0f0' : 'white',
                    borderBottom: '1px solid #eee',
                    fontSize: '14px',
                    fontWeight: !filterPondId ? 'bold' : 'normal',
                  }}
                >
                  -- Tất cả ao --
                </div>
                {filteredPonds.map((pond) => (
                  <div
                    key={pond.pond_id}
                    onClick={() => handleSelectPond(pond.pond_id, pond.pond_name, pond.pond_code)}
                    style={{
                      padding: '8px 12px',
                      cursor: 'pointer',
                      backgroundColor: filterPondId === pond.pond_id ? '#e3f2fd' : 'white',
                      borderBottom: '1px solid #eee',
                      fontSize: '14px',
                      color: filterPondId === pond.pond_id ? '#1976d2' : '#333',
                      fontWeight: filterPondId === pond.pond_id ? 'bold' : 'normal',
                    }}
                  >
                    {pond.pond_code} - {pond.pond_name}
                  </div>
                ))}
                {filteredPonds.length === 0 && (
                  <div style={{ padding: '8px 12px', color: '#999', fontSize: '14px' }}>
                    Không tìm thấy ao
                  </div>
                )}
              </div>
            )}
          </div>

          {/* Status Filter (Simple Select) */}
          <div className="form-group" style={{ margin: 0 }}>
            <label style={{ fontSize: '12px', fontWeight: 600, marginBottom: 4, display: 'block' }}>Lọc theo trạng thái</label>
            <select
              className="input"
              value={filterStatus}
              onChange={(e) => setFilterStatus(e.target.value)}
              style={{ margin: 0 }}
            >
              <option value="">-- Tất cả trạng thái --</option>
              <option value="RUNNING">🔄 RUNNING</option>
              <option value="FINISHED">✓ FINISHED</option>
            </select>
          </div>

          {/* Searchable Shrimp Type Filter */}
          <div className="form-group" style={{ margin: 0, position: 'relative' }}>
            <label style={{ fontSize: '12px', fontWeight: 600, marginBottom: 4, display: 'block' }}>Lọc theo loại tôm</label>
            <div style={{ display: 'flex', alignItems: 'center', gap: 0 }}>
              <input
                className="input"
                type="text"
                value={filterShrimpTypeSearch}
                onChange={(e) => {
                  setFilterShrimpTypeSearch(e.target.value)
                  if (!openShrimpTypeDropdown) setOpenShrimpTypeDropdown(true)
                }}
                onFocus={() => setOpenShrimpTypeDropdown(true)}
                placeholder="Nhập loại hoặc click ▼"
                style={{ margin: 0, borderRadius: '4px 0 0 4px', flex: 1 }}
              />
              <button
                className="btn"
                onClick={() => setOpenShrimpTypeDropdown(!openShrimpTypeDropdown)}
                style={{
                  margin: 0,
                  padding: '8px 12px',
                  borderRadius: '0 4px 4px 0',
                  border: '1px solid #ddd',
                  borderLeft: 'none',
                  cursor: 'pointer',
                  backgroundColor: '#f5f5f5',
                  fontSize: '16px',
                }}
              >
                ▼
              </button>
            </div>
            {openShrimpTypeDropdown && (
              <div
                style={{
                  position: 'absolute',
                  top: '100%',
                  left: 0,
                  right: 0,
                  backgroundColor: 'white',
                  border: '1px solid #ddd',
                  borderRadius: '4px',
                  marginTop: '4px',
                  maxHeight: '200px',
                  overflowY: 'auto',
                  zIndex: 10,
                  boxShadow: '0 4px 6px rgba(0,0,0,0.1)',
                }}
              >
                <div
                  onClick={() => {
                    setFilterShrimpType('')
                    setFilterShrimpTypeSearch('')
                    setOpenShrimpTypeDropdown(false)
                  }}
                  style={{
                    padding: '8px 12px',
                    cursor: 'pointer',
                    backgroundColor: !filterShrimpType ? '#f0f0f0' : 'white',
                    borderBottom: '1px solid #eee',
                    fontSize: '14px',
                    fontWeight: !filterShrimpType ? 'bold' : 'normal',
                  }}
                >
                  -- Tất cả loại --
                </div>
                {filteredShrimpTypes.map((type) => (
                  <div
                    key={type}
                    onClick={() => handleSelectShrimpType(type)}
                    style={{
                      padding: '8px 12px',
                      cursor: 'pointer',
                      backgroundColor: filterShrimpType === type ? '#e3f2fd' : 'white',
                      borderBottom: '1px solid #eee',
                      fontSize: '14px',
                      color: filterShrimpType === type ? '#1976d2' : '#333',
                      fontWeight: filterShrimpType === type ? 'bold' : 'normal',
                    }}
                  >
                    {type}
                  </div>
                ))}
                {filteredShrimpTypes.length === 0 && (
                  <div style={{ padding: '8px 12px', color: '#999', fontSize: '14px' }}>
                    Không tìm thấy loại tôm
                  </div>
                )}
              </div>
            )}
          </div>

          {/* Season Name Search */}
          <div className="form-group" style={{ margin: 0 }}>
            <label style={{ fontSize: '12px', fontWeight: 600, marginBottom: 4, display: 'block' }}>Tìm theo tên mùa vụ</label>
            <input
              className="input"
              type="text"
              value={filterSeasonName}
              onChange={(e) => setFilterSeasonName(e.target.value)}
              placeholder="VD: Mùa 1"
              style={{ margin: 0 }}
            />
          </div>
        </div>

        {(filterPondId || filterStatus || filterShrimpType || filterSeasonName) && (
          <button
            className="btn btn-secondary"
            onClick={resetFilters}
            style={{ padding: '6px 12px', fontSize: '12px' }}
          >
            🔄 Xóa bộ lọc
          </button>
        )}
      </div>

      <div className="card">
        <h3>Danh sách mùa vụ</h3>
        {filteredSeasons.length !== seasons.length && (
          <p style={{ margin: '0 0 12px 0', color: '#666', fontSize: '14px' }}>
            📊 Đang hiển thị {filteredSeasons.length}/{seasons.length} mùa vụ
          </p>
        )}
        <div className="table-responsive">
          <table className="table">
            <thead>
              <tr>
                <th>Ao</th>
                <th>Tên mùa vụ</th>
                <th>Loại tôm</th>
                <th>Ngày thả</th>
                <th>Mật độ</th>
                <th>Dự kiến Thu hoạch</th>
                <th>Trạng thái</th>
                <th>Hành động</th>
              </tr>
            </thead>
            <tbody>
              {loading ? (
                <tr><td colSpan="8">Đang tải...</td></tr>
              ) : filteredSeasons.length === 0 ? (
                <tr><td colSpan="8">{seasons.length === 0 ? 'Chưa có mùa vụ nào' : 'Không có mùa vụ nào phù hợp với bộ lọc'}</td></tr>
              ) : (
                filteredSeasons.map((season) => (
                  <tr key={season.season_id}>
                    <td>{getPondName(season.pond_id)}</td>
                    <td>{season.season_name}</td>
                    <td>{season.shrimp_type}</td>
                    <td>{formatVietnameseDate(season.start_date)}</td>
                    <td>{formatRoundedNumber(season.density)}</td>
                    <td>{formatVietnameseDate(season.expected_harvest)}</td>
                    <td>
                      <span style={{
                        padding: '4px 8px',
                        borderRadius: '4px',
                        backgroundColor: season.status === 'RUNNING' ? '#d1fae5' : '#f3e8ff',
                        color: season.status === 'RUNNING' ? '#065f46' : '#6b21a8',
                        fontSize: '12px',
                        fontWeight: 'bold',
                      }}>
                        {season.status === 'RUNNING' ? '🔄 RUNNING' : '✓ FINISHED'}
                      </span>
                    </td>
                    <td style={{ display: 'flex', gap: 8 }}>
                      {season.status === 'RUNNING' && (
                        <button className="btn btn-success" onClick={() => openHarvestModal(season)}>Thu hoạch</button>
                      )}
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
      </div>

      {/* Create Season Modal */}
      {showCreateModal && (
        <div className="modal" onClick={() => setShowCreateModal(false)}>
          <div className="modal-content" onClick={(e) => e.stopPropagation()} style={{ maxWidth: 720 }}>
            <h3 style={{ marginTop: 0 }}>Tạo mùa vụ mới</h3>
            <form onSubmit={handleCreateSubmit}>
              <div className="form-group">
                <label>Ao nuôi</label>
                <select className="input" value={createForm.pondId} onChange={(e) => handleCreateChange('pondId', e.target.value)} required>
                  <option value="">-- Chọn ao --</option>
                  {ponds.map((pond) => (
                    <option key={pond.pond_id} value={pond.pond_id}>
                      {pond.pond_code} - {pond.pond_name}
                    </option>
                  ))}
                </select>
              </div>

              <div className="form-group">
                <label>Tên mùa vụ</label>
                <input className="input" value={createForm.seasonName} onChange={(e) => handleCreateChange('seasonName', e.target.value)} placeholder="VD: Mùa 1/2024" required />
              </div>

              <div className="form-group">
                <label>Ngày thả (Start Date)</label>
                <input className="input" type="date" value={createForm.startDate} onChange={(e) => handleCreateChange('startDate', e.target.value)} required />
              </div>

              <div className="form-group">
                <label>Loại tôm</label>
                <input className="input" value={createForm.shrimpType} onChange={(e) => handleCreateChange('shrimpType', e.target.value)} placeholder="VD: Tôm sú, Tôm thẻ chân trắng" required />
              </div>

              <div className="form-group">
                <label>Mật độ</label>
                <input className="input" type="number" step="0.01" value={createForm.density} onChange={(e) => handleCreateChange('density', e.target.value)} placeholder="Mật độ nuôi (con/m²)" required />
              </div>

              <div style={{ display: 'flex', gap: '10px', marginTop: '20px' }}>
                <button type="submit" className="btn btn-primary" style={{ flex: 1 }} disabled={saving}>
                  💾 {saving ? 'Đang tạo' : 'Tạo mùa vụ'}
                </button>
                <button type="button" className="btn btn-secondary" style={{ flex: 1 }} onClick={() => setShowCreateModal(false)}>
                  ❌ Hủy
                </button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* Harvest Season Modal */}
      {showHarvestModal && selectedSeason && (
        <div className="modal" onClick={() => setShowHarvestModal(false)}>
          <div className="modal-content" onClick={(e) => e.stopPropagation()} style={{ maxWidth: 600 }}>
            <h3 style={{ marginTop: 0 }}>Thu hoạch mùa vụ</h3>
            <form onSubmit={handleHarvestSubmit}>
              <div style={{ backgroundColor: '#f0f9ff', padding: '12px', borderRadius: '4px', marginBottom: '16px' }}>
                <p style={{ margin: '4px 0' }}><strong>Ao:</strong> {getPondName(selectedSeason.pond_id)}</p>
                <p style={{ margin: '4px 0' }}><strong>Mùa vụ:</strong> {selectedSeason.season_name}</p>
                <p style={{ margin: '4px 0' }}><strong>Loại tôm:</strong> {selectedSeason.shrimp_type}</p>
                <p style={{ margin: '4px 0' }}><strong>Ngày thả:</strong> {formatVietnameseDate(selectedSeason.start_date)}</p>
              </div>

              <div className="form-group">
                <label>Ngày Thu hoạch (Actual Harvest)</label>
                <input className="input" type="date" value={harvestForm.actualHarvestDate} onChange={(e) => handleHarvestChange('actualHarvestDate', e.target.value)} required />
              </div>

              <div className="form-group">
                <label>Ghi chú</label>
                <textarea className="input" value={harvestForm.note} onChange={(e) => handleHarvestChange('note', e.target.value)} placeholder="Ghi chú về mùa vụ (tùy chọn)" rows="3"></textarea>
              </div>

              <div style={{ display: 'flex', gap: '10px', marginTop: '20px' }}>
                <button type="submit" className="btn btn-success" style={{ flex: 1 }} disabled={saving}>
                  🎯 {saving ? 'Đang lưu' : 'Thu hoạch'}
                </button>
                <button type="button" className="btn btn-secondary" style={{ flex: 1 }} onClick={() => setShowHarvestModal(false)}>
                  ❌ Hủy
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  )
}

export default ManagerSeasons
